	using namespace std;

	int n;

	int d[10000];

	int find(int L, int R, int k) {

	    int x = rand() % (R - L + 1) + L;

	    swap(d[L], d[x]);

	    int a = L + 1, b = R;

	    while (a < b) {

	        while (a < b && d[a] < d[L])

	            ++a;

	        while (a < b && d[b] >= d[L])

	            --b;

	        swap(d[a], d[b]);

